import{_ as a,c as t,o as i,ag as n}from"./chunks/framework.S-Qvb3wi.js";const h=JSON.parse('{"title":"Retention Labels: Automated Application Guide","description":"","frontmatter":{},"headers":[],"relativePath":"enterprise/retention-labels/automated-tagging.md","filePath":"enterprise/retention-labels/automated-tagging.md"}'),o={name:"enterprise/retention-labels/automated-tagging.md"};function l(s,e,r,c,p,d){return i(),t("div",null,e[0]||(e[0]=[n(`<h1 id="retention-labels-automated-application-guide" tabindex="-1">Retention Labels: Automated Application Guide <a class="header-anchor" href="#retention-labels-automated-application-guide" aria-label="Permalink to &quot;Retention Labels: Automated Application Guide&quot;">​</a></h1><p>This guide explains how to use the API to automatically apply retention labels to archived emails, enabling automated compliance and retention management workflows.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Automated retention label application allows external systems and services to programmatically tag emails with appropriate retention labels based on content analysis, business rules, or regulatory requirements. This eliminates manual tagging for large volumes of emails while ensuring consistent retention policy enforcement.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><h3 id="_1-financial-document-classification" tabindex="-1">1. Financial Document Classification <a class="header-anchor" href="#_1-financial-document-classification" aria-label="Permalink to &quot;1. Financial Document Classification&quot;">​</a></h3><p><strong>Scenario</strong>: Automatically identify and tag financial documents (invoices, receipts, payment confirmations) with extended retention periods for regulatory compliance.</p><p><strong>Implementation</strong>:</p><ul><li>Monitor newly ingested emails for financial keywords in subject lines or attachment names</li><li>Apply &quot;Financial Records&quot; label (typically 7+ years retention) to matching emails</li><li>Use content analysis to identify financial document types</li></ul><h3 id="_2-legal-and-compliance-tagging" tabindex="-1">2. Legal and Compliance Tagging <a class="header-anchor" href="#_2-legal-and-compliance-tagging" aria-label="Permalink to &quot;2. Legal and Compliance Tagging&quot;">​</a></h3><p><strong>Scenario</strong>: Apply legal hold labels to emails related to ongoing litigation or regulatory investigations.</p><p><strong>Implementation</strong>:</p><ul><li>Scan emails for legal-related keywords or specific case references</li><li>Tag emails from/to legal departments with &quot;Legal Hold&quot; labels</li><li>Apply extended retention periods to preserve evidence</li></ul><h3 id="_3-executive-communication-preservation" tabindex="-1">3. Executive Communication Preservation <a class="header-anchor" href="#_3-executive-communication-preservation" aria-label="Permalink to &quot;3. Executive Communication Preservation&quot;">​</a></h3><p><strong>Scenario</strong>: Ensure important communications involving executive leadership are retained beyond standard policies.</p><p><strong>Implementation</strong>:</p><ul><li>Identify emails from C-level executives (CEO, CFO, CTO, etc.)</li><li>Apply &quot;Executive Communications&quot; labels with extended retention</li><li>Preserve strategic business communications for historical reference</li></ul><h3 id="_4-data-classification-integration" tabindex="-1">4. Data Classification Integration <a class="header-anchor" href="#_4-data-classification-integration" aria-label="Permalink to &quot;4. Data Classification Integration&quot;">​</a></h3><p><strong>Scenario</strong>: Integrate with existing data classification systems to apply retention labels based on content sensitivity.</p><p><strong>Implementation</strong>:</p><ul><li>Use AI/ML classification results to determine retention requirements</li><li>Apply labels like &quot;Confidential&quot;, &quot;Public&quot;, or &quot;Restricted&quot; with appropriate retention periods</li><li>Automate compliance with data protection regulations</li></ul><h3 id="_5-project-based-retention" tabindex="-1">5. Project-Based Retention <a class="header-anchor" href="#_5-project-based-retention" aria-label="Permalink to &quot;5. Project-Based Retention&quot;">​</a></h3><p><strong>Scenario</strong>: Apply specific retention periods to emails related to particular projects or contracts.</p><p><strong>Implementation</strong>:</p><ul><li>Identify project-related emails using subject line patterns or participant lists</li><li>Tag with project-specific labels (e.g., &quot;Project Alpha - 5 Year Retention&quot;)</li><li>Ensure project documentation meets contractual retention requirements</li></ul><h2 id="api-workflow" tabindex="-1">API Workflow <a class="header-anchor" href="#api-workflow" aria-label="Permalink to &quot;API Workflow&quot;">​</a></h2><h3 id="step-1-authentication-setup" tabindex="-1">Step 1: Authentication Setup <a class="header-anchor" href="#step-1-authentication-setup" aria-label="Permalink to &quot;Step 1: Authentication Setup&quot;">​</a></h3><p>Create an API key with appropriate permissions:</p><ul><li>Navigate to <strong>Dashboard → Admin → Roles/Users</strong></li><li>Create a user with <code>read:archive</code> and <code>delete:archive</code> permissions (minimum required)</li><li>Generate an API for the newly created user</li><li>Securely store the API key for use in automated systems</li></ul><h3 id="step-2-identify-target-emails" tabindex="-1">Step 2: Identify Target Emails <a class="header-anchor" href="#step-2-identify-target-emails" aria-label="Permalink to &quot;Step 2: Identify Target Emails&quot;">​</a></h3><p>Use the archived emails API to find emails that need labeling:</p><p><strong>Get Recent Emails</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/v1/archived-emails?limit=100&amp;sort=archivedAt:desc</span></span></code></pre></div><p><strong>Search for Specific Emails</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/v1/archived-emails/search?query=subject:invoice&amp;limit=50</span></span></code></pre></div><h3 id="step-3-check-current-label-status" tabindex="-1">Step 3: Check Current Label Status <a class="header-anchor" href="#step-3-check-current-label-status" aria-label="Permalink to &quot;Step 3: Check Current Label Status&quot;">​</a></h3><p>Before applying a new label, verify the email&#39;s current state:</p><p><strong>Check Email Label</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/v1/enterprise/retention-policy/email/{emailId}/label</span></span></code></pre></div><p>This returns <code>null</code> if no label is applied, or the current label information if one exists.</p><h3 id="step-4-apply-retention-label" tabindex="-1">Step 4: Apply Retention Label <a class="header-anchor" href="#step-4-apply-retention-label" aria-label="Permalink to &quot;Step 4: Apply Retention Label&quot;">​</a></h3><p>Apply the appropriate label to the email:</p><p><strong>Apply Label</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /api/v1/enterprise/retention-policy/email/{emailId}/label</span></span>
<span class="line"><span>Content-Type: application/json</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;labelId&quot;: &quot;your-label-uuid-here&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="step-5-verify-application" tabindex="-1">Step 5: Verify Application <a class="header-anchor" href="#step-5-verify-application" aria-label="Permalink to &quot;Step 5: Verify Application&quot;">​</a></h3><p>Confirm the label was successfully applied by checking the response or making another GET request.</p><h2 id="label-management" tabindex="-1">Label Management <a class="header-anchor" href="#label-management" aria-label="Permalink to &quot;Label Management&quot;">​</a></h2><h3 id="getting-available-labels" tabindex="-1">Getting Available Labels <a class="header-anchor" href="#getting-available-labels" aria-label="Permalink to &quot;Getting Available Labels&quot;">​</a></h3><p>List all available retention labels to identify which ones to use:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/v1/enterprise/retention-policy/labels</span></span></code></pre></div><p>This returns all labels with their IDs, names, retention periods, and status (enabled/disabled).</p><h3 id="label-selection-strategy" tabindex="-1">Label Selection Strategy <a class="header-anchor" href="#label-selection-strategy" aria-label="Permalink to &quot;Label Selection Strategy&quot;">​</a></h3><ul><li><strong>Pre-create labels</strong> through the UI with appropriate names and retention periods</li><li><strong>Map business rules</strong> to specific label IDs in your automation logic</li><li><strong>Cache label information</strong> to avoid repeated API calls</li><li><strong>Handle disabled labels</strong> gracefully (they cannot be applied to new emails)</li></ul><h2 id="implementation-patterns" tabindex="-1">Implementation Patterns <a class="header-anchor" href="#implementation-patterns" aria-label="Permalink to &quot;Implementation Patterns&quot;">​</a></h2><h3 id="pattern-1-post-ingestion-processing" tabindex="-1">Pattern 1: Post-Ingestion Processing <a class="header-anchor" href="#pattern-1-post-ingestion-processing" aria-label="Permalink to &quot;Pattern 1: Post-Ingestion Processing&quot;">​</a></h3><p>Apply labels after emails have been fully ingested and indexed:</p><ol><li>Monitor for newly ingested emails (via webhooks or polling)</li><li>Analyze email content and metadata</li><li>Determine appropriate retention label based on business rules</li><li>Apply the label via API</li></ol><h3 id="pattern-2-batch-processing" tabindex="-1">Pattern 2: Batch Processing <a class="header-anchor" href="#pattern-2-batch-processing" aria-label="Permalink to &quot;Pattern 2: Batch Processing&quot;">​</a></h3><p>Process emails in scheduled batches:</p><ol><li>Query for unlabeled emails periodically (daily/weekly)</li><li>Process emails in manageable batches (50-100 emails)</li><li>Apply classification logic and labels</li><li>Log results for audit and monitoring</li></ol><h3 id="pattern-3-event-driven-tagging" tabindex="-1">Pattern 3: Event-Driven Tagging <a class="header-anchor" href="#pattern-3-event-driven-tagging" aria-label="Permalink to &quot;Pattern 3: Event-Driven Tagging&quot;">​</a></h3><p>React to specific events or triggers:</p><ol><li>Receive notification of specific events (legal hold notice, project start, etc.)</li><li>Search for relevant emails based on criteria</li><li>Apply appropriate labels to all matching emails</li><li>Document the mass labeling action</li></ol><h2 id="authentication-and-security" tabindex="-1">Authentication and Security <a class="header-anchor" href="#authentication-and-security" aria-label="Permalink to &quot;Authentication and Security&quot;">​</a></h2><h3 id="api-key-management" tabindex="-1">API Key Management <a class="header-anchor" href="#api-key-management" aria-label="Permalink to &quot;API Key Management&quot;">​</a></h3><ul><li><strong>Use dedicated API keys</strong> for automated systems (not user accounts)</li><li><strong>Assign minimal required permissions</strong> (<code>delete:archive</code> for label application)</li><li><strong>Rotate API keys regularly</strong> as part of security best practices</li><li><strong>Store keys securely</strong> using environment variables or secret management systems</li></ul><h3 id="request-authentication" tabindex="-1">Request Authentication <a class="header-anchor" href="#request-authentication" aria-label="Permalink to &quot;Request Authentication&quot;">​</a></h3><p>Include the API key in all requests:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Authorization: Bearer your-api-key-here</span></span>
<span class="line"><span>Content-Type: application/json</span></span></code></pre></div><h2 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h2><h3 id="common-error-scenarios" tabindex="-1">Common Error Scenarios <a class="header-anchor" href="#common-error-scenarios" aria-label="Permalink to &quot;Common Error Scenarios&quot;">​</a></h3><ul><li><strong>404 Email Not Found</strong>: The specified email ID doesn&#39;t exist</li><li><strong>404 Label Not Found</strong>: The label ID is invalid or label has been deleted</li><li><strong>409 Conflict</strong>: Attempting to apply a disabled label</li><li><strong>422 Validation Error</strong>: Invalid request format or missing required fields</li></ul><h3 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h3><ul><li><strong>Check response status codes</strong> and handle errors appropriately</li><li><strong>Implement retry logic</strong> for temporary failures (5xx errors)</li><li><strong>Log all operations</strong> for audit trails and debugging</li><li><strong>Continue processing</strong> other emails even if some fail</li></ul><h2 id="performance-considerations" tabindex="-1">Performance Considerations <a class="header-anchor" href="#performance-considerations" aria-label="Permalink to &quot;Performance Considerations&quot;">​</a></h2><h3 id="rate-limiting" tabindex="-1">Rate Limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to &quot;Rate Limiting&quot;">​</a></h3><ul><li><strong>Process emails in batches</strong> rather than individually when possible</li><li><strong>Add delays between API calls</strong> to avoid overwhelming the server</li><li><strong>Monitor API response times</strong> and adjust batch sizes accordingly</li></ul><h3 id="efficiency-tips" tabindex="-1">Efficiency Tips <a class="header-anchor" href="#efficiency-tips" aria-label="Permalink to &quot;Efficiency Tips&quot;">​</a></h3><ul><li><strong>Cache label information</strong> to reduce API calls</li><li><strong>Check existing labels</strong> before applying new ones to avoid unnecessary operations</li><li><strong>Use search API</strong> to filter emails rather than processing all emails</li><li><strong>Implement incremental processing</strong> to handle only new or modified emails</li></ul><h2 id="monitoring-and-auditing" tabindex="-1">Monitoring and Auditing <a class="header-anchor" href="#monitoring-and-auditing" aria-label="Permalink to &quot;Monitoring and Auditing&quot;">​</a></h2><h3 id="logging-recommendations" tabindex="-1">Logging Recommendations <a class="header-anchor" href="#logging-recommendations" aria-label="Permalink to &quot;Logging Recommendations&quot;">​</a></h3><ul><li><strong>Log all label applications</strong> with email ID, label ID, and timestamp</li><li><strong>Track success/failure rates</strong> for monitoring system health</li><li><strong>Record business rule matches</strong> for compliance reporting</li></ul><h3 id="audit-trail" tabindex="-1">Audit Trail <a class="header-anchor" href="#audit-trail" aria-label="Permalink to &quot;Audit Trail&quot;">​</a></h3><p>All automated label applications are recorded in the system audit log with:</p><ul><li>Actor identified as the API key name</li><li>Target email and applied label details</li><li>Timestamp of the operation</li></ul><p>This ensures full traceability of automated retention decisions.</p><h2 id="integration-examples" tabindex="-1">Integration Examples <a class="header-anchor" href="#integration-examples" aria-label="Permalink to &quot;Integration Examples&quot;">​</a></h2><h3 id="scenario-invoice-processing-system" tabindex="-1">Scenario: Invoice Processing System <a class="header-anchor" href="#scenario-invoice-processing-system" aria-label="Permalink to &quot;Scenario: Invoice Processing System&quot;">​</a></h3><ol><li><strong>Trigger</strong>: New email arrives with invoice attachment</li><li><strong>Analysis</strong>: System identifies invoice keywords or attachment types</li><li><strong>Action</strong>: Apply &quot;Financial Records - 7 Year&quot; label via API</li><li><strong>Result</strong>: Email retained for regulatory compliance period</li></ol><h3 id="scenario-legal-hold-implementation" tabindex="-1">Scenario: Legal Hold Implementation <a class="header-anchor" href="#scenario-legal-hold-implementation" aria-label="Permalink to &quot;Scenario: Legal Hold Implementation&quot;">​</a></h3><ol><li><strong>Trigger</strong>: Legal department issues hold notice for specific matter</li><li><strong>Search</strong>: Find all emails matching case criteria (participants, keywords, date range)</li><li><strong>Action</strong>: Apply &quot;Legal Hold - Matter XYZ&quot; label to all matching emails</li><li><strong>Result</strong>: All relevant emails preserved indefinitely</li></ol><h3 id="scenario-data-classification-integration" tabindex="-1">Scenario: Data Classification Integration <a class="header-anchor" href="#scenario-data-classification-integration" aria-label="Permalink to &quot;Scenario: Data Classification Integration&quot;">​</a></h3><ol><li><strong>Trigger</strong>: Content classification system processes new emails</li><li><strong>Analysis</strong>: ML system categorizes email as &quot;Confidential Financial Data&quot;</li><li><strong>Mapping</strong>: Business rules map category to &quot;Financial Confidential - 10 Year&quot; label</li><li><strong>Action</strong>: Apply label via API</li><li><strong>Result</strong>: Automatic compliance with data retention policies</li></ol><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><ol><li><strong>Set up authentication</strong> by creating an API key with appropriate permissions</li><li><strong>Identify your use cases</strong> and create corresponding retention labels through the UI</li><li><strong>Test the API</strong> with a few sample emails to understand the workflow</li><li><strong>Implement your business logic</strong> to identify which emails need which labels</li><li><strong>Deploy your automation</strong> with proper error handling and monitoring</li><li><strong>Monitor results</strong> and adjust your classification rules as needed</li></ol><p>This automated approach ensures consistent retention policy enforcement while reducing manual administrative overhead.</p>`,96)]))}const u=a(o,[["render",l]]);export{h as __pageData,u as default};
